#include <vector>
#include <algorithm>
#include <omp.h>

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    /* flatten the 2‑D vector to a single row‑major array for faster
       access while still preserving the original API. */
    int* flat = path.data()->data();

    /* pick a cache‑friendly work chunk for the outer loop */
    const int block = 64;                     // likely L2 cache line size
    #pragma omp parallel for schedule(static, block)
    for (int k = 0; k < n; ++k) {
        int* pk = flat + k * n;               // column k of rows
        for (int i = 0; i < n; ++i) {
            int aik = flat[i * n + k];
            int* row = flat + i * n;          // row i
            for (int j = 0; j < n; ++j) {
                int tmp = aik + pk[j];
                if (tmp < row[j]) row[j] = tmp;
            }
        }
    }
}
