/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B) {
    // constant factor used in the updates
    const double alpha = 1.0 / 3.0;

    // raw pointers for lower‑latency access
    double* restrict a = A.data();
    double* restrict b = B.data();

    // use two separate OpenMP parallel loops to avoid dependence issues
    for (int t = 0; t < tsteps; ++t) {
        // B update
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = alpha * (a[i-1] + a[i] + a[i+1]);
        }

        // A update
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = alpha * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
