/* Optimised LU factorisation kernel.
   Behaviour is identical to the original reference
   implementation.                                                       */
void kernel_lu(int n,
               std::vector<std::vector<double>>& A) {
    // Work on local copies of row pointers to avoid repeated bounds checks
    std::vector<double*> row(n);
    for (int i = 0; i < n; ++i) row[i] = A[i].data();

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ai = row[i];
        // first part: columns j < i
        for (int j = 0; j < i; ++j) {
            double* Aj = row[j];
            double sum = 0.0;
            for (int k = 0; k < j; ++k) {
                sum += Ai[k] * Aj[k];
            }
            Ai[j] = (Ai[j] - sum) / Aj[j];
        }
        // second part: columns j >= i
        for (int j = i; j < n; ++j) {
            double* Aj = row[j];
            double sum = 0.0;
            for (int k = 0; k < i; ++k) {
                sum += Ai[k] * Aj[k];
            }
            Ai[j] -= sum;
        }
    }
}
