// Helper to obtain a contiguous pointer to a row in a std::vector<std::vector<double>>
inline double* row_ptr(std::vector<std::vector<double>>& M, std::size_t i)
{
    return M[i].data();
}

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Parallelise over the outer dimension 'i' (rows of C). All threads
    // work on independent rows, guaranteeing no race conditions.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i)
    {
        double* Crow = row_ptr(C, i);
        const double* Arow = row_ptr(A, i);

        // Initialise C[i][j] *= beta
        for (int j = 0; j < nj; ++j)
            Crow[j] *= beta;

        // Accumulate alpha * A[i][k] * B[k][j]
        for (int k = 0; k < nk; ++k)
        {
            double a_ik = Arow[k] * alpha;
            const double* Bcol = row_ptr(B, k);
            for (int j = 0; j < nj; ++j)
                Crow[j] += a_ik * Bcol[j];
        }
    }
}
