/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(const int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {
    // Pointers to the underlying data for speed.
    double* const x1_ptr = x1.data();
    double* const x2_ptr = x2.data();
    double* const y1_ptr = y_1.data();
    double* const y2_ptr = y_2.data();
    // Flatten A so that we can avoid double indexing overhead.
    // Note: A is already a vector of vectors; we use its address directly.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum1 = 0.0;
        auto* Ai = A[i].data();          // row i
        for (int j = 0; j < n; ++j) {
            sum1 += Ai[j] * y1_ptr[j];
        }
        x1_ptr[i] += sum1;
    }

    // Second loop processes columns of A, i.e. A[j][i] in inner loop.
    // We can transpose the access by iterating over rows and columns in the same way.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum2 = 0.0;
        // iterate over rows j, access A[j][i]
        for (int j = 0; j < n; ++j) {
            sum2 += A[j][i] * y2_ptr[j];
        }
        x2_ptr[i] += sum2;
    }
}
