/* Optimized computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {
    /* Allocate temporary buffers on the stack (if small) or heap otherwise.
       We use a single buffer that holds both z and intermediate sums to
       reduce memory traffic. */
    std::vector<double> temp(n, 0.0);   // this will be used as z
    y[0] = -r[0];
    double beta = 1.0;
    double alpha = -r[0];

    for (int k = 1; k < n; ++k) {
        /* Update beta */
        beta = (1.0 - alpha * alpha) * beta;

        /* Compute the dot product sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i] */
        double sum = 0.0;
#pragma omp simd reduction(+:sum)
        for (int i = 0; i < k; ++i) {
            sum += r[k - i - 1] * y[i];
        }

        /* Update alpha */
        alpha = -(r[k] + sum) / beta;

        /* First update z[i] = y[i] + alpha * y[k-i-1] */
        for (int i = 0; i < k; ++i) {
            temp[i] = y[i] + alpha * y[k - i - 1];
        }

        /* Copy z back to y[0..k-1] */
        std::memcpy(y.data(), temp.data(), k * sizeof(double));

        /* Set the new element */
        y[k] = alpha;
    }
}
