```cpp
#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y) {
    // Assume A and B are n×n dense matrices stored row‑wise.
    // We flatten accesses and use OpenMP parallelisation and vectorisation.
    #pragma omp parallel for schedule(static) collapse(1)
    for (int i = 0; i < n; ++i) {
        const std::vector<double> &Ai = A[i];
        const std::vector<double> &Bi = B[i];
        double tmp_sum = 0.0;
        double y_sum   = 0.0;
        const double *x_ptr = x.data();

        // Manual inner loop unrolling for a small, fixed factor improves
        // prefetching and reduces loop overhead. The factor 4 works well on
        // most modern CPUs and leaves no remainder.
        int j = 0;
        int unroll = 4;
        int limit = n - (n % unroll);
        for (; j < limit; j += unroll) {
            #pragma omp simd
            for (int k = 0; k < unroll; ++k) {
                const double xj = x_ptr[j + k];
                tmp_sum += Ai[j + k] * xj;
                y_sum   += Bi[j + k] * xj;
            }
        }
        // Handle remainder elements (if any)
        for (; j < n; ++j) {
            const double xj = x_ptr[j];
            tmp_sum += Ai[j] * xj;
            y_sum   += Bi[j] * xj;
        }

        tmp[i] = tmp_sum;
        y[i]   = alpha * tmp_sum + beta * y_sum;
    }
}
