/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // => Form  B := alpha*A**T*B.
    // A is MxM
    // B is MxN

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        // Pointers to the start of the i-th rows in A and B
        double* const a_i = &A[i][0];
        double* const b_i = &B[i][0];

        for (int j = 0; j < n; ++j) {
            // Accumulate the dot-product of the i‑th column of A with the
            // i‑th row of B
            double sum = b_i[j];
            // Only rows k > i contribute
            for (int k = i + 1; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            b_i[j] = alpha * sum;
        }
    }
}
