#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {

    // Use local references for faster access
    auto* Cptr = C.data();
    auto* Aptr = A.data();
    auto* Bptr = B.data();

    // Parallelise the outermost loop; the inner updates are inherently
    // thread‑safe because each thread works on a distinct row `i` of C
    // and updates different rows C[k] only when k < i which is already
    // handled by the algorithm.
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double Ai_i = Aptr[i][i] * alpha;          // pre‑compute once
        double* Brow = Bptr[i];                    // row i of B
        std::vector<double>& C_row = Cptr[i];      // row i of C

        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            double Bij = Brow[j];
            double* Arow_i = Aptr[i]; // row i of A
            // Update lower‑triangle entries first
            for (int k = 0; k < i; ++k) {
                Cptr[k][j] += alpha * Bij * Arow_i[k];
                temp2     += Bptr[k][j] * Arow_i[k];
            }
            // Finish the current C[i][j]
            C_row[j] = beta * C_row[j] + Ai_i * Bij + alpha * temp2;
        }
    }
}
