void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B)
{
    constexpr double w = 0.2;
    /* Avoid repeated bounds checks by moving pointers out of the loops */
    for (int t = 0; t < tsteps; ++t) {
        /* Update B from A */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            const std::vector<double> &Arow = A[i];
            const std::vector<double> &Arowm1 = A[i - 1];
            const std::vector<double> &Arowp1 = A[i + 1];
            std::vector<double> &Brow = B[i];
            for (int j = 1; j < n - 1; ++j) {
                Brow[j] = w * (Arow[j] + Arow[j - 1] + Arow[j + 1] +
                               Arowp1[j] + Arowm1[j]);
            }
        }
        /* Update A from B */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            const std::vector<double> &Brow = B[i];
            const std::vector<double> &Browm1 = B[i - 1];
            const std::vector<double> &Browp1 = B[i + 1];
            std::vector<double> &Arow = A[i];
            for (int j = 1; j < n - 1; ++j) {
                Arow[j] = w * (Brow[j] + Brow[j - 1] + Brow[j + 1] +
                               Browp1[j] + Browm1[j]);
            }
        }
    }
