```cpp
#include <vector>
#include <cstring>
#include <omp.h>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* ---------- 1. compute column means ------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) {
            s += data[i][j];
        }
        mean[j] = s / static_cast<double>(n);
    }

    /* ---------- 2. center the data --------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
        }
    }

    /* ---------- 3. compute covariance matrix ------------------------------ */
    const double denom = 1.0 / static_cast<double>(n - 1);

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* cov_i = cov[i].data();
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double value = sum * denom;
            cov_i[j] = value;
            cov[j][i] = value;               // symmetry
        }
    }
}
