#include <vector>
#include <cstddef>
#include <immintrin.h>   // for AVX2 intrinsics

/* Helper to access flattened triangular matrix */
static inline double  &L_elem(double *L, std::size_t n, std::size_t i, std::size_t j) {
    return L[i * n + j];
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& Lv,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    /* Create a flattened view of L for better cache behaviour.
       Only allocate once per call to avoid reallocations. */
    const std::size_t N = static_cast<std::size_t>(n);
    std::vector<double> L_flat(N * N);
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j <= i; ++j) {
            L_flat[i * n + j] = Lv[i][j];
        }
    }

    /* Triangular solve: forward substitution */
    for (int i = 0; i < n; ++i) {
        double sum = b[i];
        int j = 0;

        /* Process in chunks of 4 for vectorisation (AVX2). */
        int vec_end = (i & ~3);
        for (; j < vec_end; j += 4) {
            __m256d L_vec = _mm256_loadu_pd(&L_flat[i * n + j]); // L[i][j..j+3]
            __m256d x_vec  = _mm256_loadu_pd(&x[j]);              // x[j..j+3]
            __m256d prod   = _mm256_mul_pd(L_vec, x_vec);
            __m256d tmp    = _mm256_hadd_pd(prod, prod);
            __m256d sumv   = _mm256_hadd_pd(tmp, tmp);
            double block_sum;
            _mm256_storeu_pd(reinterpret_cast<double*>(&block_sum), sumv);
            sum -= block_sum;
        }
        /* Remaining scalar tail */
        for (; j < i; ++j) {
            sum -= L_flat[i * n + j] * x[j];
        }
        x[i] = sum / L_flat[i * n + i];
    }
}
