/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    /* {
        1) Use raw pointers for fast indexing
        2) Parallelise over the outermost loop (n)
        3) Keep the inner partially unrolled for the lower triangle
    } */

#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *Ci = C[i].data();           // C[i][0..]
        const double *Ai = A[i].data();     // A[i][0..]

        /* Scale the part of C that will be updated */
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        /* Compute the rank‑m update */
        for (int k = 0; k < m; ++k) {
            const double aik = Ai[k];
            /* pointer to column k of A for rows 0..i */
            const double *Ak = &A[0][k];
            for (int j = 0; j <= i; ++j) {
                Ci[j] += alpha * aik * Ak[j * m + 0];   /* Ak[j] = A[j][k] */
            }
        }
    }
}
