#include <vector>
#include <algorithm>
#include <cstring>

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {
    // Use raw pointer access for speed
    int *matrow[32];                // assume n <= 32*32, adjust if needed
    for (int i = 0; i < n; ++i) {
        matrow[i] = table[i].data();
    }

    // Inline match function
    auto match = [](int b1, int b2) -> int {
        return (b1 + b2 == 3) ? 1 : 0;
    };

    for (int i = n - 1; i >= 0; --i) {
        int *rowi = matrow[i];
        for (int j = i + 1; j < n; ++j) {
            int best = 0;

            // value from left cell
            int tmp = rowi[j - 1];
            if (tmp > best) best = tmp;

            // value from top cell
            tmp = matrow[i + 1][j];
            if (tmp > best) best = tmp;

            // value from diagonal cell + match
            if (i < j - 1) {
                tmp = matrow[i + 1][j - 1] + match(seq[i], seq[j]);
                if (tmp > best) best = tmp;
            } else {
                tmp = matrow[i + 1][j - 1];
                if (tmp > best) best = tmp;
            }

            // split points
            for (int k = i + 1; k < j; ++k) {
                tmp = rowi[k] + matrow[k + 1][j];
                if (tmp > best) best = tmp;
            }

            rowi[j] = best;
        }
    }
}
