/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r)
{
    /* Ensure the input containers have the expected size */
    if (s.size() < (size_t)m) s.resize(m);
    if (q.size() < (size_t)n) q.resize(n);

    /* 1. compute s[j] = sum_i r[i] * A[i][j] */
#ifdef _OPENMP
    #pragma omp parallel for schedule(static)
#endif
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i)
            sum += r[i] * A[i][j];
        s[j] = sum;
    }

    /* 2. compute q[i] = sum_j (A[i][j] + p[j]) */
#ifdef _OPENMP
    #pragma omp parallel for schedule(static)
#endif
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const std::vector<double>& row = A[i];
        for (int j = 0; j < m; ++j)
            sum += row[j] + p[j];
        q[i] = sum;
    }
}
