void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A)
{
    // Alias to speed repeated indexing
    std::vector<double*> row(n);
    for (int i = 0; i < n; ++i)
        row[i] = A[i].data();          // pointer to the i‑th row

    const double inv9 = 1.0 / 9.0;

