        {
            double* const cur   = row[i];
            double* const prev  = row[i-1];
            double* const next  = row[i+1];

            // vectorised inner loop (auto SIMD / unroll by 4)
#pragma omp simd
            for (int j = 1; j <= n - 2; ++j)
            {
                // sum of the 3x3 neighbourhood
                cur[j] = ( prev[j-1] + prev[j] + prev[j+1] +
                           cur[j-1]                  + cur[j]   + cur[j+1] +
                           next[j-1] + next[j] + next[j+1] ) * inv9;
            }
        }
    }
