/* Main computational kernel: Modified Gram–Schmidt QR decomposition.
   The function signature is kept unchanged to match the harness. */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    /* Basic argument checks – they are cheap and help catch misuse. */
    assert(m > 0 && n > 0);
    assert(static_cast<int>(A.size())   == m);
    assert(static_cast<int>(R.size())   == n);
    assert(static_cast<int>(Q.size())   == m);
    for (int i = 0; i < m; ++i) { assert(static_cast<int>(A[i].size()) == n); }
    for (int i = 0; i < n; ++i) { assert(static_cast<int>(R[i].size()) == n); }
    for (int i = 0; i < m; ++i) { assert(static_cast<int>(Q[i].size()) == n); }

    /* ``cols[i]`` points to the i‑th column of A, Q, and R as a contiguous
       array when the 2‑D vectors are stored row‑wise.  This small helper
       lets the compiler issue more efficient memory accesses. */
    const std::vector<double> *A_cols   [n];
    std::vector<double>       *Q_cols   [m];
    std::vector<double>       *R_cols   [n];
    for (int j = 0; j < n; ++j) A_cols[j] = &A[j];
    for (int i = 0; i < m; ++i) Q_cols[i] = &Q[i];
    for (int j = 0; j < n; ++j) R_cols[j] = &R[j];

    /* Parallel outer loop over the columns */
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        /* Compute the norm of column k of A */
        double nrm = 0.0;
        for (int i = 0; i < m; ++i) {
            double v = A[i][k];
            nrm += v * v;
        }
        R[k][k] = std::sqrt(nrm);

        /* Normalise the column and store it in Q */
        double inv = 1.0 / R[k][k];
        #pragma omp simd
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] * inv;
        }

        /* Orthogonalise the remaining columns */
        for (int j = k + 1; j < n; ++j) {
            double dot = 0.0;
            for (int i = 0; i < m; ++i) {
                dot += Q[i][k] * A[i][j];
            }
            R[k][j] = dot;

            #pragma omp simd
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * dot;
            }
        }
    }
}
