/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp)
{
    // Reset y to zero
    // Use a simple loop here – the reset is a very small part of the cost.
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j)
        y[j] = 0.0;

    // Main computation.
    // We do the two loops over `j` in the same pass over `i`.
    // The outer loop is parallelised and the contribution to `y`
    // is reduced with an array reduction (OpenMP 5.0 feature).
    #pragma omp parallel for schedule(static) reduction(+:y[:n])
    for (int i = 0; i < m; ++i)
    {
        double tmp_val = 0.0;
        // Compute tmp[i] = A[i] * x
        #pragma omp simd reduction(+:tmp_val)
        for (int j = 0; j < n; ++j)
            tmp_val += A[i][j] * x[j];

        // Accumulate y[j] += A[i][j] * tmp[i]
        #pragma omp simd
        for (int j = 0; j < n; ++j)
            y[j] += A[i][j] * tmp_val;
    }

    // Store tmp for external use (exact same behaviour as original)
    for (int i = 0; i < m; ++i)
    {
        double sum = 0.0;
        for (int j = 0; j < n; ++j)
            sum += A[i][j] * x[j];
        tmp[i] = sum;
    }
}
