void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
		std::vector<std::vector<double>>& E,
		std::vector<std::vector<double>>& A,
		std::vector<std::vector<double>>& B,
		std::vector<std::vector<double>>& F,
		std::vector<std::vector<double>>& C,
		std::vector<std::vector<double>>& D,
		std::vector<std::vector<double>>& G) {

    /* --------------------------------------------------------------------
     * Helper to get a raw pointer to the data of a 2‑D std::vector.
     * The input vectors are already contiguous row‑majorly.
     * -------------------------------------------------------------------- */
    auto ptr = [](std::vector<std::vector<double>>& v) -> double* {
        return v.empty() ? nullptr : &v[0][0];
    };

    double *Eptr = ptr(E);
    double *Aptr = ptr(A);
    double *Bptr = ptr(B);
    double *Fptr = ptr(F);
    double *Cptr = ptr(C);
    double *Dptr = ptr(D);
    double *Gptr = ptr(G);

    /* --------------------------------------------------------------------
     * kernel 1 : E = A * B   (ni × nj)  * (nk × nj) transposed?
     * -------------------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            double *aRow = At + i * nk;   // A[i][*]
            double *bCol = B + j;         // B[0..nk-1][j]
            for (int k = 0; k < nk; ++k) {
                sum += aRow[k] * bCol[k * nj];
            }
            Eptr[i * nj + j] = sum;
        }
    }

    /* --------------------------------------------------------------------
     * kernel 2 : F = C * D   (nj × nl)  * (nm × nl) transposed?
     * -------------------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < nj; ++i) {
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            double *cRow = C + i * nm;      // C[i][*]
            double *dCol = D + j;           // D[0..nm-1][j]
            for (int k = 0; k < nm; ++k) {
                sum += cRow[k] * dCol[k * nl];
            }
            Fptr[i * nl + j] = sum;
        }
    }

    /* --------------------------------------------------------------------
     * kernel 3 : G = E * F   (ni × nl)  * (nj × nl) transposed?
     * -------------------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            double *eRow = Eptr + i * nj;    // E[i][*]
            double *fCol = Fptr + j;         // F[0..nj-1][j]
            for (int k = 0; k < nj; ++k) {
                sum += eRow[k] * fCol[k * nl];
            }
            Gptr[i * nl + j] = sum;
        }
    }
}
