#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) {
    /* Flatten the 2‑D vector into a 1‑D array for cache efficiency */
    std::vector<double> flatA(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(A[i].begin(), A[i].end(), flatA.begin() + i * n);

    /* Helper lambda to index the flattened matrix */
    auto idx = [n](int i, int j) -> std::size_t { return i * static_cast<std::size_t>(n) + j; };

    /* --- LU Decomposition with partial pivoting disabled --- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* Upper triangle (j < i) -- compute L elements */
        for (int j = 0; j < i; ++j) {
            double w = flatA[idx(i, j)];
            for (int k = 0; k < j; ++k)
                w -= flatA[idx(i, k)] * flatA[idx(k, j)];
            flatA[idx(i, j)] = w / flatA[idx(j, j)];
        }

        /* Diagonal and upper triangle (j >= i) -- compute U elements */
        for (int j = i; j < n; ++j) {
            double w = flatA[idx(i, j)];
            for (int k = 0; k < i; ++k)
                w -= flatA[idx(i, k)] * flatA[idx(k, j)];
            flatA[idx(i, j)] = w;
        }
    }

    /* --- Forward substitution: L * y = b --- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        for (int j = 0; j < i; ++j)
            w -= flatA[idx(i, j)] * y[j];
        y[i] = w;
    }

    /* --- Backward substitution: U * x = y --- */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        for (int j = i + 1; j < n; ++j)
            w -= flatA[idx(i, j)] * x[j];
        x[i] = w / flatA[idx(i, i)];
    }

    /* Write the result back to the 2‑D representation (optional) */
    for (int i = 0; i < n; ++i)
        std::copy(flatA.begin() + i * n, flatA.begin() + (i + 1) * n, A[i].begin());
}
