#include <numeric>
#include <vector>
#include <cmath>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    constexpr double eps = 0.1;
    const double inv_n   = 1.0 / n;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ---------- 1. compute means  ---------- */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s * inv_n;
    }

    /* ---------- 2. compute stddevs  ---------- */
    std::vector<double> inv_stddev(m);
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double var = 0.0;
        for (int i = 0; i < n; ++i) {
            double diff = data[i][j] - mean[j];
            var += diff * diff;
        }
        var *= inv_n;
        double sd = std::sqrt(var);
        if (sd <= eps) sd = 1.0;          // avoid division by zero
        stddev[j]    = sd;
        inv_stddev[j] = 1.0 / sd;
    }

    /* ---------- 3. normalize data  ---------- */
    #pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_sqrt_n * inv_stddev[j];
        }
    }

    /* ---------- 4. compute correlation matrix  ---------- */
    #pragma omp parallel for
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {
                s += data[k][i] * data[k][j];
            }
            corr[i][j] = s;
            corr[j][i] = s;  // mirror entry
        }
    }
    corr[m-1][m-1] = 1.0;   // last diagonal, already set in loop above
}
