/* Main computational kernel. The function signature is unchanged
   so the harness can call it directly.  The body has been
   rewritten to use a flat indexing trick, avoid repeated
   boundary checks, and parallelise the heavy loops with OpenMP. */
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B) {

    const double coeff = 0.125;               // 1/8
    const auto Nm1 = static_cast<std::size_t>(n - 1);
    const auto Nm2 = static_cast<std::size_t>(n - 2);

    #pragma omp parallel
    {
        // local pointers to avoid repeated header lookups
        auto* const a = &A[0][0][0];
        auto* const b = &B[0][0][0];
        const std::size_t stride_i = static_cast<std::size_t>(n) * n;
        const std::size_t stride_j = static_cast<std::size_t>(n);

        for (int t = 1; t <= tsteps; ++t) {
            /* Update B from A */
            #pragma omp for collapsed(3) schedule(static)
            for (std::size_t i = 1; i < Nm2; ++i)
                for (std::size_t j = 1; j < Nm2; ++j)
                    for (std::size_t k = 1; k < Nm2; ++k) {
                        const std::size_t idx = i * stride_i + j * stride_j + k;
                        const std::size_t idx_ip1 = idx + stride_i;
                        const std::size_t idx_im1 = idx - stride_i;
                        const std::size_t idx_jp1 = idx + stride_j;
                        const std::size_t idx_jm1 = idx - stride_j;
                        const std::size_t idx_kp1 = idx + 1;
                        const std::size_t idx_km1 = idx - 1;

                        const double center = a[idx];
                        B[i][j][k] = coeff * (a[idx_ip1] - 2.0 * center + a[idx_im1]) +
                                     coeff * (a[idx_jp1] - 2.0 * center + a[idx_jm1]) +
                                     coeff * (a[idx_kp1] - 2.0 * center + a[idx_km1]) + center;
                    }

            /* Update A from B */
            #pragma omp for collapsed(3) schedule(static)
            for (std::size_t i = 1; i < Nm2; ++i)
                for (std::size_t j = 1; j < Nm2; ++j)
                    for (std::size_t k = 1; k < Nm2; ++k) {
                        const std::size_t idx = i * stride_i + j * stride_j + k;
                        const std::size_t idx_ip1 = idx + stride_i;
                        const std::size_t idx_im1 = idx - stride_i;
                        const std::size_t idx_jp1 = idx + stride_j;
                        const std::size_t idx_jm1 = idx - stride_j;
                        const std::size_t idx_kp1 = idx + 1;
