```cpp
/*  Optimized GEMVER kernel
 *
 *  The original benchmark performs three distinct matrix–vector updates:
 *      1.  A ← A + u1·v1ᵀ + u2·v2ᵀ
 *      2.  x ← x + β * Aᵀ · y          (note the transpose)
 *      3.  w ← w + α * A  · x
 *
 *  This implementation keeps the public interface unchanged while:
 *      – using contiguous flat storage for A to eliminate double‑vector indirections
 *      – employing blocking to keep the working set in L1/L2 caches
 *      – replacing the nested loops with explicit pointer arithmetic for speed
 *      – parallelising the outermost loop with OpenMP (gcc -fopenmp)
 *
 *  The algorithmic behaviour is exactly the same as the reference code.
 */

#include <vector>
#include <cstddef>
#include <omp.h>

/* Helper to convert 2‑D indices to 1‑D in row‑major order */
inline std::size_t idx(std::size_t i, std::size_t j, std::size_t n) noexcept {
    return i * n + j;
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
#pragma omp declare simd aligned(A, u1, v1, u2, v2, x, y, w) linear(i, j)
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    /* Flatten the 2‑D matrix into a 1‑D contiguous vector. */
    std::vector<double> flatA(n * n);
    for (int i = 0; i < n; ++i)
        std::copy_n(A[i].data(), n, flatA.data() + idx(i, 0, n));

    /* --------------------------------------------------------------
       1. Update A ← A + u1·v1ᵀ + u2·v2ᵀ
       -------------------------------------------------------------- */
    const int block = 64;           // cache block size
    #pragma omp parallel for schedule(static)
    for (int ii = 0; ii < n; ii += block) {
        int i_max = std::min(ii + block, n);
        for (int jj = 0; jj < n; jj += block) {
            int j_max = std::min(jj + block, n);
            for (int i = ii; i < i_max; ++i) {
                double ui1 = u1[i];
                double ui2 = u2[i];
                std::size_t base = idx(i, jj, n);
                for (int j = jj; j < j_max; ++j) {
                    flatA[base + j] += ui1 * v1[j] + ui2 * v2[j];
                }
            }
        }
    }

    /* --------------------------------------------------------------
       2. x ← x + β * Aᵀ · y   (A transposed)
       -------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double xi = x[i];
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += flatA[idx(j, i, n)] * y[j];
        }
        xi += beta * sum;
        x[i] = xi;
    }

    /* --------------------------------------------------------------
       3. w ← w + z      (element‑wise addition)
       -------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        w[i] += z[i];
    }

    /* --------------------------------------------------------------
       4. w ← w + α * A  · x
       -------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double wi = w[i];
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += flatA[idx(i, j, n)] * x[j];
        }
        wi += alpha * sum;
        w[i] = wi;
    }

    /* Write back the flattened matrix to the original 2‑D vector */
    for (int i = 0; i < n; ++i)
        std::copy_n(flatA.data() + idx(i, 0, n), n, A[i].data());
}
