/*===========================================================================*/
/* Flatten the three‑dimensional A and the two‑dimensional C4 to 1‑D
   arrays to allow high‑performance cache usage and vectorisation. */
/*===========================================================================*/
static inline double* flattenA(const std::vector<std::vector<std::vector<double>>>& A,
                               int nr, int nq, int np)
{
    double* flat = (double*)_mm_malloc(nr * nq * np * sizeof(double), 32);
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q)
            std::memcpy(flat + (r*nq + q)*np,
                        A[r][q].data(), np * sizeof(double));
    return flat;
}

static inline double* flattenC4(const std::vector<std::vector<double>>& C4,
                               int np)
{
    double* flat = (double*)_mm_malloc(np * np * sizeof(double), 32);
    for (int s = 0; s < np; ++s)
        std::memcpy(flat + s*np, C4[s].data(), np * sizeof(double));
    return flat;
}

static inline void depackA(double* flat,
                           std::vector<std::vector<std::vector<double>>>& A,
                           int nr, int nq, int np)
{
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q)
            std::memcpy(A[r][q].data(),
                        flat + (r*nq + q)*np, np * sizeof(double));
}

/*===========================================================================*/
/* Kernel implementation                                                      */
/*===========================================================================*/
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum)
{
