    double* Aflat  = flattenA(A, nr, nq, np);
    double* Cflat  = flattenC4(C4, np);
    double* sumbuf = (double*)_mm_malloc(np * sizeof(double), 32);

    /* Parallel loop over the outer two indices.  Collapse(2) yields
       one team per (r,q) pair which is ideal for the small inner
       workload. */
#pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q) {

            /* Pointers to the current row and to the C4 matrix. */
            const double* const Arq = Aflat + (r*nq + q)*np;
            const double* const C   = Cflat;

            /* Perform a matrix‑vector product for each p.  Vectorize
               the inner s‑loop using AVX2. */
            for (int p = 0; p < np; ++p) {
                __m256d acc = _mm256_setzero_pd();
                int s = 0;
                for (; s <= np - 4; s += 4) {
                    /* Load A[r][q][s..s+3] and C[s..s+3][p] */
                    __m256d a_vec = _mm256_load_pd(&Aflat[(r*nq + q)*np + s]);
                    __m256d c_vec = _mm256_broadcast_sd(&Cflat[s*np + p]); /* s is scalar index, broadcast */
                    acc = _mm256_fmadd_pd(a_vec, c_vec, acc);
                }
                /* Handle remaining elements. */
                double temp = 0.0;
                for (; s < np; ++s)
                    temp += Arq[s] * Cflat[s*np + p];
                /* Reduce AVX register and add scalar tail. */
                double tmp[4];
                _mm256_storeu_pd(tmp, acc);
                temp += tmp[0] + tmp[1] + tmp[2] + tmp[3];
                sumbuf[p] = temp;
            }

            /* Store the result back into Aflat. */
            for (int p = 0; p < np; ++p)
                Aflat[(r*nq + q)*np + p] = sumbuf[p];
        }

    /* Copy back the flattened A to the original structure and free temp
       buffers. */
    depackA(Aflat, A, nr, nq, np);
    _mm_free(Aflat);
    _mm_free(Cflat);
    _mm_free(sumbuf);
}
