#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_) {

    /* Use OpenMP to parallelise inner loops while keeping the
       sequential time‑stepping required by the simulation. */
    #pragma omp parallel
    {
        for (int t = 0; t < tmax; ++t) {
            /* 1. Set source on the first row of ey */
            #pragma omp for schedule(static)
            for (int j = 0; j < ny; ++j) {
                ey[0][j] = _fict_[t];
            }

            /* 2. Update ey for i > 0 */
            #pragma omp for collapse(2) schedule(static)
            for (int i = 1; i < nx; ++i) {
                for (int j = 0; j < ny; ++j) {
                    ey[i][j] -= 0.5 * (hz[i][j] - hz[i - 1][j]);
                }
            }

            /* 3. Update ex for j > 0 */
            #pragma omp for collapse(2) schedule(static)
            for (int i = 0; i < nx; ++i) {
                for (int j = 1; j < ny; ++j) {
                    ex[i][j] -= 0.5 * (hz[i][j] - hz[i][j - 1]);
                }
            }

            /* 4. Update hz */
            #pragma omp for collapse(2) schedule(static)
            for (int i = 0; i < nx - 1; ++i) {
                for (int j = 0; j < ny - 1; ++j) {
                    hz[i][j] -= 0.7 *
                            (ex[i][j + 1] - ex[i][j]
                             + ey[i + 1][j] - ey[i][j]);
                }
            }
        }
    }
}
