#include <cstddef>
#include <vector>
#include <omp.h>

static constexpr std::size_t BLOCK_NI = 64;
static constexpr std::size_t BLOCK_NJ = 64;
static constexpr std::size_t BLOCK_NK = 64;

/* Helper to access a contiguous 2‑D array */
inline double& elem(std::vector<double>& a, std::size_t ncol, std::size_t i, std::size_t j) {
    return a[i * ncol + j];
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm( int ni, int nj, int nk, int nl,
                 double alpha, double beta,
                 std::vector<std::vector<double>>& tmp,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& D)
{
    /* ----- Flatten the input vectors to 1‑D buffers ----- */
    const std::size_t A_ni = A.size(),    A_nk = A[0].size();
    const std::size_t B_nk = B.size(),    B_nj = B[0].size();
    const std::size_t C_nj = C.size(),    C_nl = C[0].size();
    const std::size_t D_ni = D.size(),    D_nl = D[0].size();
    std::vector<double> A_buf(A_ni * A_nk), B_buf(B_nk * B_nj),
                       C_buf(C_nj * C_nl), D_buf(D_ni * D_nl),
                       tmp_buf(ni * nj);

    /* Copy to 1‑D buffers */
    #pragma omp parallel for collapse(2)
    for (std::size_t i = 0; i < (std::size_t)A_ni; ++i)
        for (std::size_t j = 0; j < (std::size_t)A_nk; ++j)
            elem(A_buf, A_nk, i, j) = A[i][j];

    #pragma omp parallel for collapse(2)
    for (std::size_t i = 0; i < (std::size_t)B_nk; ++i)
        for (std::size_t j = 0; j < (std::size_t)B_nj; ++j)
            elem(B_buf, B_nj, i, j) = B[i][j];

    #pragma omp parallel for collapse(2)
    for (std::size_t i = 0; i < (std::size_t)C_nj; ++i)
        for (std::size_t j = 0; j < (std::size_t)C_nl; ++j)
            elem(C_buf, C_nl, i, j) = C[i][j];

    #pragma omp parallel for collapse(2)
    for (std::size_t i = 0; i < (std::size_t)D_ni; ++i)
        for (std::size_t j = 0; j < (std::size_t)D_nl; ++j)
            elem(D_buf, D_nl, i, j) = D[i][j];

    /* ----- Core GEMM computation with blocking ----- */
    #pragma omp parallel for schedule(static)
    for (int ii = 0; ii < ni; ii += BLOCK_NI) {
        int i_max = ii + BLOCK_NI;
        if (i_max > ni) i_max = ni;
        for (int jj = 0; jj < nj; jj += BLOCK_NJ) {
            int j_max = jj + BLOCK_NJ;
            if (j_max > nj) j_max = nj;
            for (int kk = 0; kk < nk; kk += BLOCK_NK) {
                int k_max = kk + BLOCK_NK;
                if (k_max > nk) k_max = nk;

                for (int i = ii; i < i_max; ++i) {
                    for (int j = jj; j < j_max; ++j) {
                        double sum = elem(tmp_buf, nj, i, j);
                        for (int k = kk; k < k_max; ++k) {
                            sum += alpha * elem(A_buf, A_nk, i, k)
                                 * elem(B_buf, B_nj, k, j);
                        }
                        elem(tmp_buf, nj, i, j) = sum;
                    }
                }
            }
        }
    }

    /* ----- Final accumulation to D ----- */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nl; ++j) {
            double sum = beta * elem(D_buf, D_nl, i, j);
            for (int k = 0; k < nj; ++k) {
                sum += elem(tmp_buf, nj, i, k) * elem(C_buf, C_nl, k, j);
            }
            elem(D_buf, D_nl, i, j) = sum;
        }
    }

    /* Copy result back to the original 2‑D vector D */
    #pragma omp parallel for collapse(2)
    for (std::size_t i = 0; i < (std::size_t)D_ni; ++i)
        for (std::size_t j = 0; j < (std::size_t)D_nl; ++j)
            D[i][j] = elem(D_buf, D_nl, i, j);
}
```
This implementation:

* Flattens the 2‑D `std::vector<std::vector<double>>` into 1‑D contiguous buffers for faster cache usage.
* Uses three‑level blocking tuned for typical cache sizes (64‑element blocks).
* Parallelises outermost loops with OpenMP and enables static scheduling for load balance.
* Avoids repeated bounds checks by using raw pointer arithmetic (`elem` helper).
* Keeps the original semantics identical while considerably improving throughput on modern x86‑64 CPUs.

