#include <vector>
#include <cstddef>
#include <omp.h>

/* Flat 2‑D array layout: index(i,j) = i * stride + j */
inline constexpr std::size_t idx(std::size_t i, std::size_t j, std::size_t stride) noexcept {
    return i * stride + j;
}

/* Optimised computational kernel.
 * The interface matches the harness exactly, but internally we
 * use a one‑dimensional representation of the 2‑D matrices.
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    /* --- Helper: flatten input matrices ------------------ */
    const std::size_t N   = static_cast<std::size_t>(n);
    const std::size_t stride = N;

    /* Allocate contiguous buffers */
    std::vector<double> fu(N * N), fv(N * N), fp(N * N), fq(N * N);

    /* Copy data into flat arrays (only the interior is touched,
       but we copy the whole array for correctness). */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            std::size_t id = idx(i, j, stride);
            fu[id] = u[i][j];
            fv[id] = v[i][j];
            fp[id] = p[i][j];
            fq[id] = q[i][j];
        }

    /* --- Pre-computed constants --------------------------------- */
    const double DX = 1.0 / N;
    const double DY = 1.0 / N;
    const double DT = 1.0 / tsteps;
    const double mul1 = 2.0 * DT / (DX * DX);
    const double mul2 = DT / (DY * DY);

    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    /* --- Main time loop ----------------------------------------- */
    for (int t = 1; t <= tsteps; ++t) {

        /* ---------- First sweep (vertical) --------------------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            /* Boundary values */
            int id0   = idx(0, i, stride);
            int idn   = idx(n - 1, i, stride);
            fv[id0]   = 1.0;
            fp[id0]   = 0.0;
            fq[id0]   = fv[id0];

            /* Forward sweep (j = 1 .. n-2) */
            for (int j = 1; j < n - 1; ++j) {
                std::size_t idp = idx(i, j, stride);
                std::size_t idpjm1 = idx(i, j - 1, stride);
                std::size_t iduim1 = idx(j - 1, i - 1, stride); // note swapped indices
                std::size_t idui   = idx(j,   i, stride);
                std::size_t iduip1 = idx(j + 1, i, stride);

                double denom = a * fp[idpjm1] + b;
                fp[idp] = -c / denom;
                fq[idp] = (-d * fu[iduim1] +
                           (1.0 + 2.0 * d) * fu[idui] -
                           f * fu[iduip1] -
                           a * fq[idpjm1]) / denom;
            }

            /* Boundary at j = n-1 */
            fv[idn] = 1.0;

            /* Backward sweep (j = n-2 .. 1) */
            for (int j = n - 2; j >= 1; --j) {
                std::size_t idv = idx(j, i, stride);
                std::size_t idvp1 = idx(j + 1, i, stride);
                std::size_t idp = idx(i, j, stride);
                fv[idv] = fp[idp] * fv[idvp1] + fq[idp];
            }
        }

        /* ---------- Second sweep (horizontal) ------------------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            int idi0 = idx(i, 0, stride);
            int idiN = idx(i, n - 1, stride);
            fu[idi0] = 1.0;
            fp[idi0] = 0.0;
            fq[idi0] = fu[idi0];

            for (int j = 1; j < n - 1; ++j) {
                std::size_t idp = idx(i, j, stride);
                std::size_t idpjm1 = idx(i, j - 1, stride);
                std::size_t idvim1 = idx(i - 1, j, stride);
                std::size_t idvi   = idx(i,     j, stride);
                std::size_t idvip1 = idx(i + 1, j, stride);

                double denom = d * fp[idpjm1] + e;
                fp[idp] = -f / denom;
                fq[idp] = (-a * fv[idvim1] +
                           (1.0 + 2.0 * a) * fv[idvi] -
                           c * fv[idvip1] -
                           d * fq[idpjm1]) / denom;
            }

            fu[idiN] = 1.0;
            for (int j = n - 2; j >= 1; --j) {
                std::size_t idu = idx(i, j, stride);
                std::size_t idup1 = idx(i, j + 1, stride);
                std::size_t idp = idx(i, j, stride);
                fu[idu] = fp[idp] * fu[idup1] + fq[idp];
            }
        }
    }

    /* ---------- Copy results back to the original vectors ------ */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            std::size_t id = idx(i, j, stride);
            u[i][j] = fu[id];
            v[i][j] = fv[id];
            p[i][j] = fp[id];
            q[i][j] = fq[id];
        }
}
