```cpp
#include <cmath>
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 *  Optimised version of the Deriche recursive filter.
 *  The code keeps the original signature and the exact semantics
 *  of the reference implementation, but works on contiguous buffers
 *  and exploits OpenMP parallelism.
 */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* ----------------------------------------------------------
       Compute all scalar constants once. All are float for speed.
       ---------------------------------------------------------- */
    const float exp_a = std::exp(-alpha);
    const float exp_2a = std::exp(-2.0 * alpha);
    const float k = 1.0f - exp_a * (1.0f - exp_a) /
                           (1.0f + 2.0f * alpha * exp_a - exp_2a);

    const float a1 = k, a5 = k;
    const float a2 = k * exp_a * (float(alpha) - 1.0f), a6 = a2;
    const float a3 = k * exp_a * (float(alpha) + 1.0f), a7 = a3;
    const float a4 = a8 = -k * exp_2a;
    const float b1 = std::pow(2.0f, -(float)alpha);
    const float b2 = -exp_2a;
    const float c1 = 1.0f, c2 = 1.0f;

    /* ----------------------------------------------------------
       Work on contiguous memory to avoid bounds checks.
       ---------------------------------------------------------- */
    std::vector<float> in(w * h);
    std::vector<float> out(w * h);
    std::vector<float> buf1(w * h);   // tmp for forward pass
    std::vector<float> buf2(w * h);   // tmp for backward pass

    /* flatten input, allocate output (if not already allocated) */
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            in[i*h + j] = imgIn[i][j];

    /* ----------------------------------------------------------
       1. Forward pass along rows (y1)
       ---------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        int base = i*h;
        for (int j = 0; j < h; ++j) {
            const float x = in[base + j];
            const float y = a1*x + a2*xm1 + b1*ym1 + b2*ym2;
            buf1[base + j] = y;
            xm1  = x;
            ym2  = ym1;
            ym1  = y;
        }
    }

    /* ----------------------------------------------------------
       2. Backward pass along rows (y2)
       ---------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        int base = i*h;
        for (int jj = h-1; jj >= 0; --jj) {
            const float x = in[base + jj];
            const float y = a3*xp1 + a4*xp2 + b1*yp1 + b2*yp2;
            buf2[base + jj] = y;
            xp2 = xp1;   xp1 = x;
            yp2 = yp1;   yp1 = y;
        }
    }

    /* ----------------------------------------------------------
       3. First accumulation pass
       ---------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            const int idx = i*h + j;
            out[idx] = c1 * (buf1[idx] + buf2[idx]);
        }
    }

    /* ----------------------------------------------------------
       4. Forward pass along columns (y1) using intermediate output
       ---------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const int idx = i*h + j;
            const float x = out[idx];
            const float y = a5*x + a6*tm1 + b1*ym1 + b2*ym2;
            buf1[idx]  = y;
            tm1 = x; ym2 = ym1; ym1 = y;
        }
    }

    /* ----------------------------------------------------------
       5. Backward pass along columns (y2) using intermediate output
       ---------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int ii = w-1; ii >= 0; --ii) {
            const int idx = ii*h + j;
            const float x = out[idx];
            const float y = a7*tp1 + a8*tp2 + b1*yp1 + b2*yp2;
            buf2[idx] = y;
            tp2 = tp1; tp1 = x;
            yp2 = yp1; yp1 = y;
        }
    }

    /* ----------------------------------------------------------
       6. Final accumulation
       ---------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            const int idx = i*h + j;
            out[idx] = c2 * (buf1[idx] + buf2[idx]);
        }
    }

    /* ----------------------------------------------------------
       7. Copy back into the output matrix
       ---------------------------------------------------------- */
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = out[i*h + j];
}
